mapper.select:
SELECT DATE_FORMAT(dt.OCCUR_DATE, '%Y-%m-%d') AS STAT_DATE, dt.ERROR_TYPE, COUNT(*) AS CNT FROM ( SELECT DATE(h.OCCUR_AT) AS OCCUR_DATE, ec.ERROR_CODE_NM AS ERROR_TYPE FROM f_error_history_t h JOIN b_error_code_t ec ON h.ERROR_CODE_ID = ec.ERROR_CODE_ID JOIN r_device_t d ON h.DEVICE_ID = d.DEVICE_ID WHERE h.OCCUR_AT >= #{startDate} AND h.OCCUR_AT <= CONCAT(#{endDate}, ' 23:59:59')
UNION ALL SELECT DATE(e.OCCUR_AT) AS OCCUR_DATE, ec.ERROR_CODE_NM AS ERROR_TYPE FROM f_error_t e JOIN b_error_code_t ec ON e.ERROR_CODE_ID = ec.ERROR_CODE_ID JOIN r_device_t d ON e.DEVICE_ID = d.DEVICE_ID WHERE e.OCCUR_AT >= #{startDate} AND e.OCCUR_AT <= CONCAT(#{endDate}, ' 23:59:59')
) dt GROUP BY dt.OCCUR_DATE, dt.ERROR_TYPE ORDER BY dt.OCCUR_DATE

SELECT dt.HOUR_VAL AS STAT_HOUR, dt.ERROR_TYPE, COUNT(*) AS CNT FROM ( SELECT HOUR(h.OCCUR_AT) AS HOUR_VAL, ec.ERROR_CODE_NM AS ERROR_TYPE FROM f_error_history_t h JOIN b_error_code_t ec ON h.ERROR_CODE_ID = ec.ERROR_CODE_ID JOIN r_device_t d ON h.DEVICE_ID = d.DEVICE_ID WHERE h.OCCUR_AT >= #{startDate} AND h.OCCUR_AT <= CONCAT(#{endDate}, ' 23:59:59')
UNION ALL SELECT HOUR(e.OCCUR_AT) AS HOUR_VAL, ec.ERROR_CODE_NM AS ERROR_TYPE FROM f_error_t e JOIN b_error_code_t ec ON e.ERROR_CODE_ID = ec.ERROR_CODE_ID JOIN r_device_t d ON e.DEVICE_ID = d.DEVICE_ID WHERE e.OCCUR_AT >= #{startDate} AND e.OCCUR_AT <= CONCAT(#{endDate}, ' 23:59:59')
) dt GROUP BY dt.HOUR_VAL, dt.ERROR_TYPE ORDER BY dt.HOUR_VAL

SELECT dt.HOUR_VAL AS HOUR_OF_DAY, COUNT(*) AS CNT FROM ( SELECT HOUR(h.OCCUR_AT) AS HOUR_VAL FROM f_error_history_t h JOIN r_device_t d ON h.DEVICE_ID = d.DEVICE_ID WHERE h.OCCUR_AT >= #{startDate} AND h.OCCUR_AT <= CONCAT(#{endDate}, ' 23:59:59')
UNION ALL SELECT HOUR(e.OCCUR_AT) AS HOUR_VAL FROM f_error_t e JOIN r_device_t d ON e.DEVICE_ID = d.DEVICE_ID WHERE e.OCCUR_AT >= #{startDate} AND e.OCCUR_AT <= CONCAT(#{endDate}, ' 23:59:59')
) dt GROUP BY dt.HOUR_VAL ORDER BY dt.HOUR_VAL

SELECT dt.DOW_VAL AS DAY_OF_WEEK, COUNT(*) AS CNT FROM ( SELECT DAYOFWEEK(h.OCCUR_AT) AS DOW_VAL FROM f_error_history_t h JOIN r_device_t d ON h.DEVICE_ID = d.DEVICE_ID WHERE h.OCCUR_AT >= #{startDate} AND h.OCCUR_AT <= CONCAT(#{endDate}, ' 23:59:59')
UNION ALL SELECT DAYOFWEEK(e.OCCUR_AT) AS DOW_VAL FROM f_error_t e JOIN r_device_t d ON e.DEVICE_ID = d.DEVICE_ID WHERE e.OCCUR_AT >= #{startDate} AND e.OCCUR_AT <= CONCAT(#{endDate}, ' 23:59:59')
) dt GROUP BY dt.DOW_VAL ORDER BY dt.DOW_VAL
